 EmbeddingSimilarity {
    fn similarity(&self, i: usize, j: usize) -> f32 {
        if i >= self.embeddings.len() || j >= self.embeddings.len() {
            return 0.0;
        }
        cosine_similarity(&self.embeddings[i], &self.embeddings[j])
    }
